data: {"jsonrpc":"2.0","method":"session/update","params":{"sessionId":"0389c8ef-8826-485f-b6e9-2192feb5ec74","update":{"availableCommands":[{"description":"Use this skill to configure the Claude Code harness via settings.json. Automated behaviors (\"from now on when X\", \"each time X\", \"whenever X\", \"before/after X\") require hooks configured in settings.json - the harness executes these, not Claude, so memory/preferences cannot fulfill them. Also use for: permissions (\"allow X\", \"add permission\", \"move permission to\"), env vars (\"set X=Y\"), hook troubleshooting, or any changes to settings.json/settings.local.json files. Examples: \"allow npm commands\", \"add bq permission to global settings\", \"move permission to user settings\", \"set DEBUG=true\", \"when claude stops show X\". For simple settings like theme/model, use Config tool. (bundled)","input":null,"name":"update-config"},{"description":"Enable debug logging for this session and help diagnose issues (bundled)","input":{"hint":"[issue description]"},"name":"debug"},{"description":"Review changed code for reuse, quality, and efficiency, then fix any issues found. (bundled)","input":null,"name":"simplify"},{"description":"Research and plan a large-scale change, then execute it in parallel across 5–30 isolated worktree agents that each open a PR. (bundled)","input":{"hint":"<instruction>"},"name":"batch"},{"description":"Run a prompt or slash command on a recurring interval (e.g. /loop 5m /foo, defaults to 10m) (bundled)","input":{"hint":"[interval] <prompt>"},"name":"loop"},{"description":"Create, update, list, or run scheduled remote agents (triggers) that execute on a cron schedule. (bundled)","input":null,"name":"schedule"},{"description":"Build apps with the Claude API or Anthropic SDK.\nTRIGGER when: code imports `anthropic`/`@anthropic-ai/sdk`/`claude_agent_sdk`, or user asks to use Claude API, Anthropic SDKs, or Agent SDK.\nDO NOT TRIGGER when: code imports `openai`/other AI SDK, general programming, or ML/data-science tasks. (bundled)","input":null,"name":"claude-api"},{"description":"Clear conversation history but keep a summary in context. Optional: /compact [instructions for summarization]","input":{"hint":"<optional custom summarization instructions>"},"name":"compact"},{"description":"Show current context usage","input":null,"name":"context"},{"description":"Dump the JS heap to ~/Desktop","input":null,"name":"heapdump"},{"description":"Initialize a new CLAUDE.md file with codebase documentation","input":null,"name":"init"},{"description":"Get comments from a GitHub pull request","input":null,"name":"pr-comments"},{"description":"Review a pull request","input":null,"name":"review"},{"description":"Complete a security review of the pending changes on the current branch","input":null,"name":"security-review"},{"description":"Generate a report analyzing your Claude Code sessions","input":null,"name":"insights"}],"sessionUpdate":"available_commands_update"}}}

